 25 | impl Drop for TerminalGuard {
 26 |     fn drop(&mut self) {
 27 |         let _ = disable_raw_mode();
 28 |         let mut stdout = io::stdout();
 29 |         let _ = execute!(stdout, LeaveAlternateScreen, crossterm::event::DisableMouseCapture);
 30 |     }
