 33 | fn extract_message_text(content: &[ContentPart]) -> String {
 34 |     let mut out = String::new();
 35 |     for part in content {
 36 |         match part {
 37 |             ContentPart::Text { text } | ContentPart::Thinking { text } => {
 38 |                 if !out.is_empty() {
 39 |                     out.push('\n');
 40 |                 }
 41 |                 out.push_str(text);
 42 |             }
 43 |             ContentPart::ToolCall {
 44 |                 name, arguments, ..
 45 |             } => {
 46 |                 if !out.is_empty() {
 47 |                     out.push('\n');
 48 |                 }
 49 |                 out.push_str(&format!("Tool call: {name} {arguments}"));
 50 |             }
 51 |             ContentPart::ToolResult { content, .. } => {
 52 |                 if !out.is_empty() {
 53 |                     out.push('\n');
 54 |                 }
 55 |                 out.push_str(content);
 56 |             }
 57 |             ContentPart::Image { url, .. } => {
 58 |                 if !out.is_empty() {
 59 |                     out.push('\n');
 60 |                 }
 61 |                 out.push_str(&format!("[image: {url}]"));
 62 |             }
 63 |             ContentPart::File { path, .. } => {
 64 |                 if !out.is_empty() {
 65 |                     out.push('\n');
 66 |                 }
 67 |                 out.push_str(&format!("[file: {path}]"));
 68 |             }
 69 |         }
 70 |     }
 71 |     out
 72 | }
