 74 | fn sync_messages_from_session(app: &mut App, session: &Session) {
 75 |     app.state.messages = session
 76 |         .messages
 77 |         .iter()
 78 |         .filter_map(|msg| {
 79 |             let content = extract_message_text(&msg.content);
 80 |             if content.trim().is_empty() {
 81 |                 return None;
 82 |             }
 83 |             let message_type = match msg.role {
 84 |                 Role::User => MessageType::User,
 85 |                 Role::Assistant => MessageType::Assistant,
 86 |                 Role::System | Role::Tool => MessageType::System,
 87 |             };
 88 |             Some(ChatMessage::new(message_type, content))
 89 |         })
 90 |         .collect();
 91 |     app.state.scroll_to_bottom();
 92 | }
