 94 | fn truncate_preview(text: &str, max_chars: usize) -> String {
 95 |     let mut chars = text.chars();
 96 |     let preview: String = chars.by_ref().take(max_chars).collect();
 97 |     if chars.next().is_some() {
 98 |         format!("{preview}…")
 99 |     } else {
100 |         preview
101 |     }
102 | }
