104 | async fn send_worker_bridge_cmd(
105 |     worker_bridge: &Option<TuiWorkerBridge>,
106 |     cmd: WorkerBridgeCmd,
107 | ) -> bool {
108 |     if let Some(bridge) = worker_bridge {
109 |         bridge.cmd_tx.send(cmd).await.is_ok()
110 |     } else {
111 |         false
112 |     }
113 | }
