115 | fn sync_worker_bridge_agents(app: &mut App, worker_bridge: &Option<TuiWorkerBridge>) {
116 |     if worker_bridge.is_none() {
117 |         return;
118 |     }
119 | 
120 |     let mut desired = std::collections::HashSet::new();
121 |     desired.insert("tui".to_string());
122 | 
123 |     for message in &app.state.bus_log.entries {
124 |         if message.kind == "READY" && let Some(agent) = message.summary.split_whitespace().next() {
125 |             desired.insert(agent.to_string());
126 |         }
127 |     }
128 | 
129 |     let current = app.state.worker_bridge_registered_agents.clone();
130 |     for name in desired.difference(&current) {
131 |         if let Some(bridge) = worker_bridge.as_ref() {
132 |             let _ = bridge.cmd_tx.try_send(WorkerBridgeCmd::RegisterAgent {
133 |                 name: name.clone(),
134 |                 instructions: format!("Protocol-observed A2A agent {name}"),
135 |             });
136 |         }
137 |     }
138 |     for name in current.difference(&desired) {
139 |         if let Some(bridge) = worker_bridge.as_ref() {
140 |             let _ = bridge
141 |                 .cmd_tx
142 |                 .try_send(WorkerBridgeCmd::DeregisterAgent { name: name.clone() });
143 |         }
144 |     }
145 |     app.state.worker_bridge_registered_agents = desired;
146 | }
