148 | fn normalize_slash_command(input: &str) -> String {
149 |     match input.trim() {
150 |         "/h" | "/?" => "/help".to_string(),
151 |         "/s" => "/sessions".to_string(),
152 |         "/w" => "/swarm".to_string(),
153 |         "/r" => "/ralph".to_string(),
154 |         "/b" | "/buslog" | "/logs" => "/bus".to_string(),
155 |         "/p" => "/protocol".to_string(),
156 |         "/set" => "/settings".to_string(),
157 |         "/sym" => "/symbols".to_string(),
158 |         other => other.to_string(),
159 |     }
160 | }
