162 | async fn refresh_sessions(app: &mut App, cwd: &std::path::Path) {
163 |     match list_sessions_for_directory(cwd).await {
164 |         Ok(sessions) => {
165 |             app.state.sessions = sessions;
166 |             if app.state.selected_session >= app.state.filtered_sessions().len() {
167 |                 app.state.selected_session = app.state.filtered_sessions().len().saturating_sub(1);
168 |             }
169 |         }
170 |         Err(err) => {
171 |             app.state.status = format!("Failed to list sessions: {err}");
172 |             app.state.sessions.clear();
173 |             app.state.selected_session = 0;
174 |         }
175 |     }
176 | }
