183 | fn symbol_search_active(app: &App) -> bool {
184 |     !app.state.symbol_search.query.is_empty()
185 |         || !app.state.symbol_search.results.is_empty()
186 |         || app.state.symbol_search.loading
187 |         || app.state.symbol_search.error.is_some()
188 | }
