190 | async fn refresh_symbol_search(app: &mut App) {
191 |     app.state.symbol_search.loading = true;
192 |     let result = LspTool::new()
193 |         .execute(serde_json::json!({
194 |             "action": "workspaceSymbol",
195 |             "query": app.state.symbol_search.query.clone(),
196 |         }))
197 |         .await;
198 | 
199 |     match result {
200 |         Ok(tool_result) if tool_result.success => {
201 |             let results = tool_result
202 |                 .output
203 |                 .lines()
204 |                 .skip(2)
205 |                 .filter_map(|line| {
206 |                     let trimmed = line.trim();
207 |                     if trimmed.is_empty() {
208 |                         return None;
209 |                     }
210 |                     Some(crate::tui::symbol_search::SymbolEntry {
211 |                         name: trimmed.to_string(),
212 |                         kind: "Symbol".to_string(),
213 |                         path: std::path::PathBuf::from(trimmed),
214 |                         uri: None,
215 |                         line: None,
216 |                         container: None,
217 |                     })
218 |                 })
219 |                 .collect();
220 |             app.state.symbol_search.set_results(results);
221 |         }
222 |         Ok(tool_result) => app.state.symbol_search.set_error(tool_result.output),
223 |         Err(err) => app.state.symbol_search.set_error(err.to_string()),
224 |     }
225 | }
