227 | async fn handle_slash_command(app: &mut App, cwd: &std::path::Path, command: &str) {
228 |     match normalize_slash_command(command).as_str() {
229 |         "/help" => {
230 |             app.state.show_help = true;
231 |             app.state.help_scroll.offset = 0;
232 |             app.state.status = "Help".to_string();
233 |         }
234 |         "/sessions" | "/session" => {
235 |             refresh_sessions(app, cwd).await;
236 |             app.state.clear_session_filter();
237 |             app.state.set_view_mode(ViewMode::Sessions);
238 |             app.state.status = "Session picker".to_string();
239 |         }
240 |         "/swarm" => app.state.set_view_mode(ViewMode::Swarm),
241 |         "/ralph" => app.state.set_view_mode(ViewMode::Ralph),
242 |         "/bus" | "/protocol" => {
243 |             app.state.set_view_mode(ViewMode::Bus);
244 |             app.state.status = "Protocol bus log".to_string();
245 |         }
246 |         "/settings" => app.state.set_view_mode(ViewMode::Settings),
247 |         "/lsp" => app.state.set_view_mode(ViewMode::Lsp),
248 |         "/rlm" => app.state.set_view_mode(ViewMode::Rlm),
249 |         "/chat" | "/home" => return_to_chat(app),
250 |         "/symbols" | "/symbol" => {
251 |             app.state.symbol_search.open();
252 |             app.state.status = "Symbol search".to_string();
253 |         }
254 |         "/new" => {
255 |             app.state.messages.clear();
256 |             app.state.chat_scroll = 0;
257 |             app.state.status = "New chat buffer".to_string();
258 |             app.state.set_view_mode(ViewMode::Chat);
259 |         }
260 |         "/keys" => {
261 |             app.state.status =
262 |                 "Protocol-first commands: /protocol /bus /sessions /swarm /ralph /symbols /settings /lsp /rlm /chat /new"
263 |                     .to_string();
264 |         }
265 |         other => {
266 |             app.state.status = format!("Unknown command: {other}");
267 |         }
268 |     }
269 | }
