271 | pub async fn run(project: Option<std::path::PathBuf>) -> anyhow::Result<()> {
272 |     if let Some(project) = project {
273 |         std::env::set_current_dir(&project)?;
274 |     }
275 | 
276 |     enable_raw_mode()?;
277 |     let _guard = TerminalGuard;
278 | 
279 |     let mut stdout = io::stdout();
280 |     execute!(
281 |         stdout,
282 |         EnterAlternateScreen,
283 |         crossterm::event::EnableMouseCapture
284 |     )?;
285 | 
286 |     let backend = CrosstermBackend::new(stdout);
287 |     let mut terminal = Terminal::new(backend)?;
288 |     terminal.clear()?;
289 | 
290 |     let registry = ProviderRegistry::from_vault().await.ok().map(Arc::new);
291 |     let cwd = std::env::current_dir().unwrap_or_default();
292 |     let bus = AgentBus::new().into_arc();
293 |     let mut bus_handle = bus.handle("tui");
294 |     let mut worker_bridge = TuiWorkerBridge::spawn(None, None, None, Arc::clone(&bus))
295 |         .await
296 |         .ok()
297 |         .flatten();
298 | 
299 |     let mut session = match Session::last_for_directory(Some(&cwd)).await {
300 |         Ok(existing) => existing,
301 |         Err(_) => Session::new().await?,
302 |     };
303 | 
304 |     let (event_tx, mut event_rx) = mpsc::channel::<SessionEvent>(256);
305 |     let (result_tx, mut result_rx) = mpsc::channel::<anyhow::Result<Session>>(8);
306 | 
307 |     let mut app = App::default();
308 |     app.state.cwd_display = cwd.display().to_string();
309 |     app.state.session_id = Some(session.id.clone());
310 |     sync_messages_from_session(&mut app, &session);
311 |     refresh_sessions(&mut app, &cwd).await;
312 |     if let Some(bridge) = worker_bridge.as_ref() {
313 |         app.state
314 |             .set_worker_bridge(bridge.worker_id.clone(), bridge.worker_name.clone());
315 |         app.state.register_worker_agent("tui".to_string());
316 |         let _ = send_worker_bridge_cmd(
317 |             &worker_bridge,
318 |             WorkerBridgeCmd::RegisterAgent {
319 |                 name: "tui".to_string(),
320 |                 instructions: "Primary CodeTether TUI protocol worker".to_string(),
321 |             },
322 |         )
323 |         .await;
324 |     }
325 |     if app.state.messages.is_empty() {
326 |         app.state.status = "Ready — type a message, or use /help for commands.".to_string();
327 |     } else {
328 |         app.state.status = "Loaded previous workspace session".to_string();
329 |     }
330 |     app.state.move_cursor_end();
331 |     app.state.refresh_slash_suggestions();
332 | 
333 |     loop {
334 |         while let Some(envelope) = bus_handle.try_recv() {
335 |             app.state.bus_log.ingest(&envelope);
336 |         }
337 |         sync_worker_bridge_agents(&mut app, &worker_bridge);
338 | 
339 |         if let Some(bridge) = worker_bridge.as_mut() {
340 |             while let Ok(task) = bridge.task_rx.try_recv() {
341 |                 let preview = format!(
342 |                     "{} from {}",
343 |                     task.task_id,
344 |                     task.from_agent.clone().unwrap_or_else(|| "unknown".to_string())
345 |                 );
346 |                 app.state.push_recent_task(preview);
347 |                 app.state.enqueue_worker_task(task);
348 |                 app.state.status = format!(
349 |                     "Queued remote task(s): {}",
350 |                     app.state.worker_task_queue.len()
351 |                 );
352 |             }
353 |         }
354 | 
355 |         if !app.state.processing && let Some(task) = app.state.dequeue_worker_task() {
356 |             let from_agent = task.from_agent.unwrap_or_else(|| "unknown".to_string());
357 |             app.state.messages.push(ChatMessage::new(
358 |                 MessageType::System,
359 |                 format!(
360 |                     "Incoming A2A task {} from {}\n{}",
361 |                     task.task_id, from_agent, task.message
362 |                 ),
363 |             ));
364 |             app.state.status = format!("Received remote task {}", task.task_id);
365 |             app.state.scroll_to_bottom();
366 |         }
367 | 
368 |         while let Ok(updated_session) = result_rx.try_recv() {
369 |             match updated_session {
370 |                 Ok(updated_session) => {
371 |                     session = updated_session;
372 |                     app.state.session_id = Some(session.id.clone());
373 |                     let _ = session.save().await;
374 |                     refresh_sessions(&mut app, &cwd).await;
375 |                 }
376 |                 Err(err) => {
377 |                     app.state.processing = false;
378 |                     app.state.sync_worker_bridge_processing(false);
379 |                     let _ = send_worker_bridge_cmd(&worker_bridge, WorkerBridgeCmd::SetProcessing(false)).await;
380 |                     app.state
381 |                         .messages
382 |                         .push(ChatMessage::new(MessageType::Error, err.to_string()));
383 |                     app.state.status = "Request failed".to_string();
384 |                     app.state.scroll_to_bottom();
385 |                 }
386 |             }
387 |         }
388 | 
389 |         while let Ok(evt) = event_rx.try_recv() {
390 |             match evt {
391 |                 SessionEvent::Thinking => {
392 |                     app.state.processing = true;
393 |                     app.state.sync_worker_bridge_processing(true);
394 |                     let _ = send_worker_bridge_cmd(&worker_bridge, WorkerBridgeCmd::SetProcessing(true)).await;
395 |                     app.state.status = "Thinking…".to_string();
396 |                 }
397 |                 SessionEvent::ToolCallStart { name, arguments } => {
398 |                     app.state.processing = true;
399 |                     app.state.sync_worker_bridge_processing(true);
400 |                     let _ = send_worker_bridge_cmd(&worker_bridge, WorkerBridgeCmd::SetProcessing(true)).await;

401 |                     app.state.status = format!("Running tool: {name}");
402 |                     let args_preview = truncate_preview(&arguments, 240);
403 |                     app.state.messages.push(ChatMessage::new(
404 |                         MessageType::System,
405 |                         format!("Tool start: {name}\nArgs: {args_preview}"),
406 |                     ));
407 |                     app.state.scroll_to_bottom();
408 |                 }
409 |                 SessionEvent::ToolCallComplete {
410 |                     name,
411 |                     output,
412 |                     success,
413 |                 } => {
414 |                     let output_preview = truncate_preview(&output, 600);
415 |                     app.state.messages.push(ChatMessage::new(
416 |                         if success {
417 |                             MessageType::System
418 |                         } else {
419 |                             MessageType::Error
420 |                         },
421 |                         format!(
422 |                             "Tool {}: {name}\nOutput: {output_preview}",
423 |                             if success { "complete" } else { "failed" }
424 |                         ),
425 |                     ));
426 |                     app.state.status = format!("Tool finished: {name}");
427 |                     app.state.scroll_to_bottom();
428 |                 }
429 |                 SessionEvent::TextChunk(_) => {}
430 |                 SessionEvent::TextComplete(text) => {
431 |                     app.state
432 |                         .messages
433 |                         .push(ChatMessage::new(MessageType::Assistant, text));
434 |                     app.state.status = "Assistant replied".to_string();
435 |                     app.state.scroll_to_bottom();
436 |                 }
437 |                 SessionEvent::ThinkingComplete(text) => {
438 |                     if !text.is_empty() {
439 |                         app.state.messages.push(ChatMessage::new(
440 |                             MessageType::System,
441 |                             format!("Thinking:\n{}", truncate_preview(&text, 600)),
442 |                         ));
443 |                         app.state.scroll_to_bottom();
444 |                     }
445 |                 }
446 |                 SessionEvent::UsageReport {
447 |                     model,
448 |                     prompt_tokens,
449 |                     completion_tokens,
450 |                     duration_ms,
451 |                 } => {
452 |                     app.state.status = format!(
453 |                         "Completed with model {model} • {} in / {} out • {} ms",
454 |                         prompt_tokens, completion_tokens, duration_ms
455 |                     );
456 |                 }
457 |                 SessionEvent::SessionSync(updated) => {
458 |                     session = *updated;
459 |                     app.state.session_id = Some(session.id.clone());
460 |                 }
461 |                 SessionEvent::Done => {
462 |                     app.state.processing = false;
463 |                     app.state.sync_worker_bridge_processing(false);
464 |                     let _ = send_worker_bridge_cmd(&worker_bridge, WorkerBridgeCmd::SetProcessing(false)).await;
465 |                     app.state.status = "Ready".to_string();
466 |                 }
467 |                 SessionEvent::Error(err) => {
468 |                     app.state.processing = false;
469 |                     app.state.sync_worker_bridge_processing(false);
470 |                     let _ = send_worker_bridge_cmd(&worker_bridge, WorkerBridgeCmd::SetProcessing(false)).await;
471 |                     app.state
472 |                         .messages
473 |                         .push(ChatMessage::new(MessageType::Error, err.clone()));
474 |                     app.state.status = "Error".to_string();
475 |                     app.state.scroll_to_bottom();
476 |                 }
477 |             }
478 |         }
479 | 
480 |         terminal.draw(|f| ui(f, &mut app))?;
481 | 
482 |         if event::poll(Duration::from_millis(50))? {
483 |             match event::read()? {
484 |                 Event::Key(key) if key.kind == KeyEventKind::Press => match key.code {
485 |                     KeyCode::Char('c') if key.modifiers.contains(KeyModifiers::CONTROL) => break,
486 |                     KeyCode::Char('q') if key.modifiers.contains(KeyModifiers::CONTROL) => break,
487 |                     KeyCode::Char('t') if key.modifiers.contains(KeyModifiers::CONTROL) => {
488 |                         app.state.symbol_search.open();
489 |                         app.state.status = "Symbol search".to_string();
490 |                     }
491 |                     KeyCode::Esc => {
492 |                         if symbol_search_active(&app) {
493 |                             app.state.symbol_search.close();
494 |                             app.state.status = "Closed symbol search".to_string();
495 |                         } else if app.state.show_help {
496 |                             app.state.show_help = false;
497 |                             app.state.status = "Closed help".to_string();
498 |                         } else {
499 |                             match app.state.view_mode {
500 |                                 ViewMode::Sessions => {
501 |                                     app.state.clear_session_filter();
502 |                                     return_to_chat(&mut app);
503 |                                 }
504 |                                 ViewMode::Swarm if app.state.swarm.detail_mode => app.state.swarm.exit_detail(),
505 |                                 ViewMode::Ralph if app.state.ralph.detail_mode => app.state.ralph.exit_detail(),
506 |                                 ViewMode::Bus if app.state.bus_log.filter_input_mode => {
507 |                                     app.state.bus_log.exit_filter_mode();
508 |                                     app.state.status = "Protocol filter closed".to_string();
509 |                                 }
510 |                                 ViewMode::Bus if app.state.bus_log.detail_mode => app.state.bus_log.exit_detail(),
511 |                                 ViewMode::Chat => app.state.input_mode = InputMode::Normal,
512 |                                 _ => return_to_chat(&mut app),
513 |                             }
514 |                         }
515 |                     }
516 |                     KeyCode::Tab if app.state.slash_suggestions_visible() => {
517 |                         if app.state.apply_selected_slash_suggestion() {
518 |                             app.state.status = "Command autocompleted".to_string();
519 |                         }
520 |                     }
521 |                     KeyCode::Char('?') => {
522 |                         app.state.show_help = !app.state.show_help;
523 |                         app.state.help_scroll.offset = 0;
524 |                         app.state.status = if app.state.show_help {
525 |                             "Help".to_string()
526 |                         } else {
527 |                             "Closed help".to_string()
528 |                         };
529 |                     }
530 |                     KeyCode::Up if symbol_search_active(&app) => app.state.symbol_search.select_prev(),
531 |                     KeyCode::Up if app.state.view_mode == ViewMode::Sessions => {
532 |                         app.state.sessions_select_prev();
533 |                     }
534 |                     KeyCode::Up if app.state.slash_suggestions_visible() => {
535 |                         app.state.select_prev_slash_suggestion();
536 |                     }
537 |                     KeyCode::Up if app.state.view_mode == ViewMode::Chat && !app.state.processing => {
538 |                         let _ = app.state.history_prev();
539 |                     }
540 |                     KeyCode::Up if app.state.show_help => app.state.help_scroll.scroll_up(1),
541 |                     KeyCode::Up => match app.state.view_mode {
542 |                         ViewMode::Swarm => {
543 |                             if app.state.swarm.detail_mode {
544 |                                 app.state.swarm.detail_scroll_up(1);
545 |                             } else {
546 |                                 app.state.swarm.select_prev();
547 |                             }
548 |                         }
549 |                         ViewMode::Ralph => {
550 |                             if app.state.ralph.detail_mode {
551 |                                 app.state.ralph.detail_scroll_up(1);
552 |                             } else {
553 |                                 app.state.ralph.select_prev();
554 |                             }
555 |                         }
556 |                         ViewMode::Bus if !app.state.bus_log.filter_input_mode => {
557 |                             if app.state.bus_log.detail_mode {
558 |                                 app.state.bus_log.detail_scroll_up(1);
559 |                             } else {
560 |                                 app.state.bus_log.select_prev();
561 |                             }
562 |                         }
563 |                         _ => app.state.scroll_up(1),
564 |                     },
565 |                     KeyCode::Down if symbol_search_active(&app) => app.state.symbol_search.select_next(),
566 |                     KeyCode::Down if app.state.view_mode == ViewMode::Sessions => {
567 |                         app.state.sessions_select_next();
568 |                     }
569 |                     KeyCode::Down if app.state.slash_suggestions_visible() => {
570 |                         app.state.select_next_slash_suggestion();
571 |                     }
572 |                     KeyCode::Down if app.state.view_mode == ViewMode::Chat && !app.state.processing => {
573 |                         let _ = app.state.history_next();
574 |                     }
575 |                     KeyCode::Down if app.state.show_help => app.state.help_scroll.scroll_down(1, 200),
576 |                     KeyCode::Down => match app.state.view_mode {
577 |                         ViewMode::Swarm => {
578 |                             if app.state.swarm.detail_mode {
579 |                                 app.state.swarm.detail_scroll_down(1);
580 |                             } else {
581 |                                 app.state.swarm.select_next();
582 |                             }
583 |                         }
584 |                         ViewMode::Ralph => {
