 78 | fn sync_messages_from_session(app: &mut App, session: &Session) {
 79 |     app.state.messages = session
 80 |         .messages
 81 |         .iter()
 82 |         .filter_map(|msg| {
 83 |             let content = extract_message_text(&msg.content);
 84 |             if content.trim().is_empty() {
 85 |                 return None;
 86 |             }
 87 |             let message_type = match msg.role {
 88 |                 Role::User => MessageType::User,
 89 |                 Role::Assistant => MessageType::Assistant,
 90 |                 Role::System | Role::Tool => MessageType::System,
 91 |             };
 92 |             Some(ChatMessage::new(message_type, content))
 93 |         })
 94 |         .collect();
 95 |     app.state.scroll_to_bottom();
 96 | }
