118 | fn sync_worker_bridge_agents(app: &mut App, worker_bridge: &Option<TuiWorkerBridge>) {
119 |     let Some(bridge) = worker_bridge.as_ref() else {
120 |         return;
121 |     };
122 | 
123 |     let mut desired = std::collections::HashSet::new();
124 |     desired.insert("tui".to_string());
125 | 
126 |     for message in &app.state.bus_log.entries {
127 |         if message.kind == "READY"
128 |             && let Some(agent) = message.summary.split_whitespace().next()
129 |         {
130 |             desired.insert(agent.to_string());
131 |         }
132 |     }
133 | 
134 |     let current = app.state.worker_bridge_registered_agents.clone();
135 |     for name in desired.difference(&current) {
136 |         let _ = bridge.cmd_tx.try_send(WorkerBridgeCmd::RegisterAgent {
137 |             name: name.clone(),
138 |             instructions: format!("Protocol-observed A2A agent {name}"),
139 |         });
140 |     }
141 |     for name in current.difference(&desired) {
142 |         let _ = bridge
143 |             .cmd_tx
144 |             .try_send(WorkerBridgeCmd::DeregisterAgent { name: name.clone() });
145 |     }
146 |     app.state.worker_bridge_registered_agents = desired;
147 | }
