152 |         "/s" => "/sessions".to_string(),
153 |         "/w" => "/swarm".to_string(),
154 |         "/r" => "/ralph".to_string(),
155 |         "/b" | "/buslog" | "/logs" => "/bus".to_string(),
156 |         "/p" => "/protocol".to_string(),
157 |         "/set" => "/settings".to_string(),
158 |         "/sym" => "/symbols".to_string(),
159 |         other => other.to_string(),
160 |     }
