191 | async fn refresh_symbol_search(app: &mut App) {
192 |     app.state.symbol_search.loading = true;
193 |     let result = LspTool::new()
194 |         .execute(serde_json::json!({
195 |             "action": "workspaceSymbol",
196 |             "query": app.state.symbol_search.query.clone(),
197 |         }))
198 |         .await;
199 | 
200 |     match result {
201 |         Ok(tool_result) if tool_result.success => {
202 |             let results = tool_result
203 |                 .output
204 |                 .lines()
205 |                 .skip(2)
206 |                 .filter_map(|line| {
207 |                     let trimmed = line.trim();
208 |                     if trimmed.is_empty() {
209 |                         return None;
210 |                     }
211 |                     Some(crate::tui::symbol_search::SymbolEntry {
212 |                         name: trimmed.to_string(),
213 |                         kind: "Symbol".to_string(),
214 |                         path: std::path::PathBuf::from(trimmed),
215 |                         uri: None,
216 |                         line: None,
217 |                         container: None,
218 |                     })
219 |                 })
220 |                 .collect();
221 |             app.state.symbol_search.set_results(results);
222 |         }
223 |         Ok(tool_result) => app.state.symbol_search.set_error(tool_result.output),
224 |         Err(err) => app.state.symbol_search.set_error(err.to_string()),
225 |     }
226 | }
