239 | async fn handle_slash_command(app: &mut App, cwd: &std::path::Path, command: &str) {
240 |     match normalize_slash_command(command).as_str() {
241 |         "/help" => {
242 |             app.state.show_help = true;
243 |             app.state.help_scroll.offset = 0;
244 |             app.state.status = "Help".to_string();
245 |         }
246 |         "/sessions" | "/session" => {
247 |             refresh_sessions(app, cwd).await;
248 |             app.state.clear_session_filter();
249 |             app.state.set_view_mode(ViewMode::Sessions);
250 |             app.state.status = "Session picker".to_string();
251 |         }
252 |         "/swarm" => app.state.set_view_mode(ViewMode::Swarm),
253 |         "/ralph" => app.state.set_view_mode(ViewMode::Ralph),
254 |         "/bus" | "/protocol" => {
255 |             app.state.set_view_mode(ViewMode::Bus);
256 |             app.state.status = "Protocol bus log".to_string();
257 |         }
258 |         "/settings" => app.state.set_view_mode(ViewMode::Settings),
259 |         "/lsp" => app.state.set_view_mode(ViewMode::Lsp),
260 |         "/rlm" => app.state.set_view_mode(ViewMode::Rlm),

261 |         "/chat" | "/home" => return_to_chat(app),
262 |         "/symbols" | "/symbol" => {
263 |             app.state.symbol_search.open();
264 |             app.state.status = "Symbol search".to_string();
265 |         }
266 |         "/new" => {
267 |             app.state.messages.clear();
268 |             app.state.chat_scroll = 0;
269 |             app.state.status = "New chat buffer".to_string();
270 |             app.state.set_view_mode(ViewMode::Chat);
271 |         }
272 |         "/keys" => {
273 |             app.state.status =
274 |                 "Protocol-first commands: /protocol /bus /sessions /swarm /ralph /symbols /settings /lsp /rlm /chat /new"
275 |                     .to_string();
276 |         }
277 |         other => {
278 |             app.state.status = format!("Unknown command: {other}");
279 |         }
280 |     }
281 | }
