283 | pub async fn run(project: Option<std::path::PathBuf>) -> anyhow::Result<()> {
284 |     if let Some(project) = project {
285 |         std::env::set_current_dir(&project)?;
286 |     }
287 | 
288 |     enable_raw_mode()?;
289 |     let _guard = TerminalGuard;
290 | 
291 |     let mut stdout = io::stdout();
292 |     execute!(
293 |         stdout,
294 |         EnterAlternateScreen,
295 |         crossterm::event::EnableMouseCapture
296 |     )?;
297 | 
298 |     let backend = CrosstermBackend::new(stdout);
299 |     let mut terminal = Terminal::new(backend)?;
300 |     terminal.clear()?;
301 | 
302 |     let registry = ProviderRegistry::from_vault().await.ok().map(Arc::new);
303 |     let cwd = std::env::current_dir().unwrap_or_default();
304 |     let bus = AgentBus::new().into_arc();
305 |     let mut bus_handle = bus.handle("tui");
306 |     let mut worker_bridge = TuiWorkerBridge::spawn(None, None, None, Arc::clone(&bus))
307 |         .await
308 |         .ok()
309 |         .flatten();
310 | 
311 |     let mut session = match Session::last_for_directory(Some(&cwd)).await {
312 |         Ok(existing) => existing,
313 |         Err(_) => Session::new().await?,
314 |     };
315 | 
316 |     let (event_tx, mut event_rx) = mpsc::channel::<SessionEvent>(256);
317 |     let (result_tx, mut result_rx) = mpsc::channel::<anyhow::Result<Session>>(8);
318 | 
319 |     let mut app = App::default();
320 |     app.state.cwd_display = cwd.display().to_string();
321 |     app.state.session_id = Some(session.id.clone());
322 |     sync_messages_from_session(&mut app, &session);
323 |     refresh_sessions(&mut app, &cwd).await;
324 |     if let Some(bridge) = worker_bridge.as_ref() {
325 |         app.state
326 |             .set_worker_bridge(bridge.worker_id.clone(), bridge.worker_name.clone());
327 |         app.state.register_worker_agent("tui".to_string());
328 |         let _ = send_worker_bridge_cmd(
329 |             &worker_bridge,
330 |             WorkerBridgeCmd::RegisterAgent {
331 |                 name: "tui".to_string(),
332 |                 instructions: "Primary CodeTether TUI protocol worker".to_string(),
333 |             },
334 |         )
335 |         .await;
336 |     }
337 |     if app.state.messages.is_empty() {
338 |         app.state.status = "Ready — type a message, or use /help for commands.".to_string();
339 |     } else {
340 |         app.state.status = "Loaded previous workspace session".to_string();
341 |     }
342 |     app.state.move_cursor_end();
343 |     app.state.refresh_slash_suggestions();
344 | 
345 |     loop {
346 |         while let Some(envelope) = bus_handle.try_recv() {
347 |             app.state.bus_log.ingest(&envelope);
348 |         }
349 |         sync_worker_bridge_agents(&mut app, &worker_bridge);
350 | 
351 |         if let Some(bridge) = worker_bridge.as_mut() {
352 |             while let Ok(task) = bridge.task_rx.try_recv() {
353 |                 let preview = format!(
354 |                     "{} from {}",
355 |                     task.task_id,
356 |                     task.from_agent
357 |                         .clone()
358 |                         .unwrap_or_else(|| "unknown".to_string())
359 |                 );
360 |                 app.state.push_recent_task(preview);
361 |                 app.state.enqueue_worker_task(task);
362 |                 app.state.status = format!(
363 |                     "Queued remote task(s): {}",
364 |                     app.state.worker_task_queue.len()
365 |                 );
366 |             }
367 |         }
368 | 
369 |         if !app.state.processing
370 |             && let Some(task) = app.state.dequeue_worker_task()
371 |         {
372 |             let from_agent = task.from_agent.unwrap_or_else(|| "unknown".to_string());
373 |             app.state.messages.push(ChatMessage::new(
374 |                 MessageType::System,
375 |                 format!(
376 |                     "Incoming A2A task {} from {}\n{}",
377 |                     task.task_id, from_agent, task.message
378 |                 ),
379 |             ));
380 |             app.state.status = format!("Received remote task {}", task.task_id);
381 |             app.state.scroll_to_bottom();
382 |         }
383 | 
384 |         while let Ok(updated_session) = result_rx.try_recv() {
385 |             match updated_session {
386 |                 Ok(updated_session) => {
387 |                     session = updated_session;
388 |                     app.state.session_id = Some(session.id.clone());
389 |                     let _ = session.save().await;
390 |                     refresh_sessions(&mut app, &cwd).await;
391 |                 }
392 |                 Err(err) => {
393 |                     handle_processing_stopped(&mut app, &worker_bridge).await;
394 |                     app.state
395 |                         .messages
396 |                         .push(ChatMessage::new(MessageType::Error, err.to_string()));
397 |                     app.state.status = "Request failed".to_string();
398 |                     app.state.scroll_to_bottom();
399 |                 }
400 |             }
401 |         }
402 | 
403 |         while let Ok(evt) = event_rx.try_recv() {
404 |             match evt {
405 |                 SessionEvent::Thinking => {
406 |                     handle_processing_started(&mut app, &worker_bridge).await;
407 |                     app.state.status = "Thinking…".to_string();
408 |                 }
409 |                 SessionEvent::ToolCallStart { name, arguments } => {
410 |                     handle_processing_started(&mut app, &worker_bridge).await;
411 |                     app.state.status = format!("Running tool: {name}");
412 |                     let args_preview = truncate_preview(&arguments, 240);
413 |                     app.state.messages.push(ChatMessage::new(
414 |                         MessageType::System,
415 |                         format!("Tool start: {name}\nArgs: {args_preview}"),
416 |                     ));
417 |                     app.state.scroll_to_bottom();
418 |                 }
419 |                 SessionEvent::ToolCallComplete {
