428 |                         } else {
429 |                             MessageType::Error
430 |                         },
431 |                         format!(
432 |                             "Tool {}: {name}\nOutput: {output_preview}",
433 |                             if success { "complete" } else { "failed" }
434 |                         ),
435 |                     ));
436 |                     app.state.status = format!("Tool finished: {name}");
437 |                     app.state.scroll_to_bottom();
438 |                 }
439 |                 SessionEvent::TextChunk(_) => {}
440 |                 SessionEvent::TextComplete(text) => {
441 |                     app.state
442 |                         .messages
443 |                         .push(ChatMessage::new(MessageType::Assistant, text));
444 |                     app.state.status = "Assistant replied".to_string();
