 37 | fn extract_message_text(content: &[ContentPart]) -> String {
 38 |     let mut out = String::new();
 39 |     for part in content {
 40 |         match part {
 41 |             ContentPart::Text { text } | ContentPart::Thinking { text } => {
 42 |                 if !out.is_empty() {
 43 |                     out.push('\n');
 44 |                 }
 45 |                 out.push_str(text);
 46 |             }
 47 |             ContentPart::ToolCall {
 48 |                 name, arguments, ..
 49 |             } => {
 50 |                 if !out.is_empty() {
 51 |                     out.push('\n');
 52 |                 }
 53 |                 out.push_str(&format!("Tool call: {name} {arguments}"));
 54 |             }
 55 |             ContentPart::ToolResult { content, .. } => {
 56 |                 if !out.is_empty() {
 57 |                     out.push('\n');
 58 |                 }
 59 |                 out.push_str(content);
 60 |             }
 61 |             ContentPart::Image { url, .. } => {
 62 |                 if !out.is_empty() {
 63 |                     out.push('\n');
 64 |                 }
 65 |                 out.push_str(&format!("[image: {url}]"));
 66 |             }
 67 |             ContentPart::File { path, .. } => {
 68 |                 if !out.is_empty() {
 69 |                     out.push('\n');
 70 |                 }
 71 |                 out.push_str(&format!("[file: {path}]"));
 72 |             }
 73 |         }
 74 |     }
 75 |     out
 76 | }
