399 |     pub fn history_prev(&mut self) -> bool {
400 |         if self.command_history.is_empty() {
401 |             return false;
402 |         }
403 |         let history_len = self.command_history.len();
404 |         let new_index = match self.history_index {
405 |             Some(index) if index > 0 => Some(index - 1),
406 |             Some(index) => Some(index),
407 |             None => Some(history_len - 1),
408 |         };
409 |         if let Some(index) = new_index {
410 |             self.history_index = Some(index);
411 |             self.input = self.command_history[index].clone();
412 |             self.input_cursor = self.input_char_count();
413 |             self.input_mode = if self.input.starts_with('/') {
414 |                 InputMode::Command
415 |             } else {
416 |                 InputMode::Editing
417 |             };
418 |             self.refresh_slash_suggestions();
419 |             return true;
420 |         }
421 |         false
422 |     }
