424 |     pub fn history_next(&mut self) -> bool {
425 |         if self.command_history.is_empty() {
426 |             return false;
427 |         }
428 |         match self.history_index {
429 |             Some(index) if index + 1 < self.command_history.len() => {
430 |                 let next = index + 1;
431 |                 self.history_index = Some(next);
432 |                 self.input = self.command_history[next].clone();
433 |             }
434 |             Some(_) => {
435 |                 self.history_index = None;
436 |                 self.input.clear();
437 |             }
438 |             None => return false,
439 |         }
440 |         self.input_cursor = self.input_char_count();
441 |         self.input_mode = if self.input.is_empty() {
442 |             InputMode::Normal
443 |         } else if self.input.starts_with('/') {
444 |             InputMode::Command
445 |         } else {
446 |             InputMode::Editing
447 |         };
448 |         self.refresh_slash_suggestions();
449 |         true
450 |     }
