helpers = '''use crate::provider::{ContentPart, Role};
use crate::session::{Session, list_sessions_for_directory};
use crate::tool::{Tool, lsp::LspTool};
use crate::tui::app::state::App;
use crate::tui::chat::message::{ChatMessage, MessageType};
use crate::tui::models::ViewMode;
use crate::tui::worker_bridge::{TuiWorkerBridge, WorkerBridgeCmd};

pub fn extract_message_text(content: &[ContentPart]) -> String {
    let mut out = String::new();
    for part in content {
        match part {
            ContentPart::Text { text } | ContentPart::Thinking { text } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(text);
            }
            ContentPart::ToolCall {
                name, arguments, ..
            } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(&format!("Tool call: {name} {arguments}"));
            }
            ContentPart::ToolResult { content, .. } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(content);
            }
            ContentPart::Image { url, .. } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(&format!("[image: {url}]"));
            }
            ContentPart::File { path, .. } => {
                if !out.is_empty() {
                    out.push('\n');
                }
                out.push_str(&format!("[file: {path}]"));
            }
        }
    }
    out
}

pub fn sync_messages_from_session(app: &mut App, session: &Session) {
    app.state.messages = session
        .messages
        .iter()
        .filter_map(|msg| {
            let content = extract_message_text(&msg.content);
            if content.trim().is_empty() {
                return None;
            }
            let message_type = match msg.role {
                Role::User => MessageType::User,
                Role::Assistant => MessageType::Assistant,
                Role::System | Role::Tool => MessageType::System,
            };
            Some(ChatMessage::new(message_type, content))
        })
        .collect();
    app.state.scroll_to_bottom();
}

pub fn truncate_preview(text: &str, max_chars: usize) -> String {
    let mut chars = text.chars();
    let preview: String = chars.by_ref().take(max_chars).collect();
    if chars.next().is_some() {
        format!("{preview}…")
    } else {
        preview
    }
}

pub async fn send_worker_bridge_cmd(
    worker_bridge: &Option<TuiWorkerBridge>,
    cmd: WorkerBridgeCmd,
) -> bool {
    match worker_bridge {
        Some(bridge) => bridge.cmd_tx.send(cmd).await.is_ok(),
        None => false,
    }
}

pub fn sync_worker_bridge_agents(app: &mut App, worker_bridge: &Option<TuiWorkerBridge>) {
    let Some(bridge) = worker_bridge.as_ref() else {
        return;
    };

    let mut desired = std::collections::HashSet::new();
    desired.insert("tui".to_string());

    for message in &app.state.bus_log.entries {
        if message.kind == "READY"
            && let Some(agent) = message.summary.split_whitespace().next()
        {
            desired.insert(agent.to_string());
        }
    }

    let current = app.state.worker_bridge_registered_agents.clone();
    for name in desired.difference(&current) {
        let _ = bridge.cmd_tx.try_send(WorkerBridgeCmd::RegisterAgent {
            name: name.clone(),
            instructions: format!("Protocol-observed A2A agent {name}"),
        });
    }
    for name in current.difference(&desired) {
        let _ = bridge
            .cmd_tx
            .try_send(WorkerBridgeCmd::DeregisterAgent { name: name.clone() });
    }
    app.state.worker_bridge_registered_agents = desired;
}

pub fn normalize_slash_command(input: &str) -> String {
    match input.trim() {
        "/h" | "/?" => "/help".to_string(),
        "/s" => "/sessions".to_string(),
        "/w" => "/swarm".to_string(),
        "/r" => "/ralph".to_string(),
        "/b" | "/buslog" | "/logs" => "/bus".to_string(),
        "/p" => "/protocol".to_string(),
        "/set" => "/settings".to_string(),
        "/sym" => "/symbols".to_string(),
        other => other.to_string(),
    }
}

pub async fn refresh_sessions(app: &mut App, cwd: &std::path::Path) {
    match list_sessions_for_directory(cwd).await {
        Ok(sessions) => {
            app.state.sessions = sessions;
            if app.state.selected_session >= app.state.filtered_sessions().len() {
                app.state.selected_session = app.state.filtered_sessions().len().saturating_sub(1);
            }
        }
        Err(err) => {
            app.state.status = format!("Failed to list sessions: {err}");
            app.state.sessions.clear();
            app.state.selected_session = 0;
        }
    }
}

pub fn return_to_chat(app: &mut App) {
    app.state.set_view_mode(ViewMode::Chat);
    app.state.status = "Back to chat".to_string();
}

pub fn symbol_search_active(app: &App) -> bool {
    !app.state.symbol_search.query.is_empty()
        || !app.state.symbol_search.results.is_empty()
        || app.state.symbol_search.loading
        || app.state.symbol_search.error.is_some()
}

pub async fn refresh_symbol_search(app: &mut App) {
    app.state.symbol_search.loading = true;
    let result = LspTool::new()
        .execute(serde_json::json!({
            "action": "workspaceSymbol",
            "query": app.state.symbol_search.query.clone(),
        }))
        .await;

    match result {
        Ok(tool_result) if tool_result.success => {
            let results = tool_result
                .output
                .lines()
                .skip(2)
                .filter_map(|line| {
                    let trimmed = line.trim();
                    if trimmed.is_empty() {
                        return None;
                    }
                    Some(crate::tui::symbol_search::SymbolEntry {
                        name: trimmed.to_string(),
                        kind: "Symbol".to_string(),
                        path: std::path::PathBuf::from(trimmed),
                        uri: None,
                        line: None,
                        container: None,
                    })
                })
                .collect();
            app.state.symbol_search.set_results(results);
        }
        Ok(tool_result) => app.state.symbol_search.set_error(tool_result.output),
        Err(err) => app.state.symbol_search.set_error(err.to_string()),
    }
}

pub async fn handle_processing_started(app: &mut App, worker_bridge: &Option<TuiWorkerBridge>) {
    app.state.processing = true;
    app.state.sync_worker_bridge_processing(true);
    let _ = send_worker_bridge_cmd(worker_bridge, WorkerBridgeCmd::SetProcessing(true)).await;
}

pub async fn handle_processing_stopped(app: &mut App, worker_bridge: &Option<TuiWorkerBridge>) {
    app.state.processing = false;
    app.state.sync_worker_bridge_processing(false);
    let _ = send_worker_bridge_cmd(worker_bridge, WorkerBridgeCmd::SetProcessing(false)).await;
}
