 37 |                 task.task_id,
 38 |                 task.from_agent
 39 |                     .clone()
 40 |                     .unwrap_or_else(|| "unknown".to_string())
 41 |             );
 42 |             app.state.push_recent_task(preview);
 43 |             app.state.enqueue_worker_task(task);
 44 |             app.state.status = format!(
 45 |                 "Queued remote task(s): {}",
 46 |                 app.state.worker_task_queue.len()
 47 |             );
 48 |         }
 49 |     }
 50 | 
 51 |     if !app.state.processing
 52 |         && let Some(task) = app.state.dequeue_worker_task()
 53 |     {
 54 |         let from_agent = task.from_agent.unwrap_or_else(|| "unknown".to_string());
 55 |         app.state.messages.push(ChatMessage::new(
 56 |             MessageType::System,
 57 |             format!(
 58 |                 "Incoming A2A task {} from {}
 59 | {}",
 60 |                 task.task_id, from_agent, task.message
 61 |             ),
 62 |         ));
 63 |         app.state.status = format!("Received remote task {}", task.task_id);
 64 |         app.state.scroll_to_bottom();
 65 |     }
 66 | 
 67 |     while let Ok(updated_session) = result_rx.try_recv() {
 68 |         match updated_session {
 69 |             Ok(updated_session) => {
 70 |                 *session = updated_session;
 71 |                 app.state.session_id = Some(session.id.clone());
 72 |                 let _ = session.save().await;
 73 |                 refresh_sessions(app, cwd).await;
 74 |             }
 75 |             Err(err) => {
 76 |                 handle_processing_stopped(app, worker_bridge).await;
 77 |                 app.state
 78 |                     .messages
 79 |                     .push(ChatMessage::new(MessageType::Error, err.to_string()));
 80 |                 app.state.status = "Request failed".to_string();
 81 |                 app.state.scroll_to_bottom();
 82 |             }
 83 |         }
 84 |     }
 85 | 
 86 |     while let Ok(evt) = event_rx.try_recv() {
 87 |         handle_session_event(app, session, worker_bridge, evt).await;
 88 |     }
 89 | }
