 91 | async fn handle_session_event(
 92 |     app: &mut App,
 93 |     session: &mut Session,
 94 |     worker_bridge: &Option<TuiWorkerBridge>,
 95 |     evt: SessionEvent,
 96 | ) {
 97 |     match evt {
 98 |         SessionEvent::Thinking => {
 99 |             handle_processing_started(app, worker_bridge).await;
100 |             app.state.status = "Thinking…".to_string();
101 |         }
102 |         SessionEvent::ToolCallStart { name, arguments } => {
103 |             handle_processing_started(app, worker_bridge).await;
104 |             app.state.status = format!("Running tool: {name}");
105 |             let args_preview = truncate_preview(&arguments, 240);
106 |             app.state.messages.push(ChatMessage::new(
107 |                 MessageType::System,
108 |                 format!(
109 |                     "Tool start: {name}
110 | Args: {args_preview}"
111 |                 ),
112 |             ));
113 |             app.state.scroll_to_bottom();
114 |         }
115 |         SessionEvent::ToolCallComplete {
116 |             name,
117 |             output,
118 |             success,
119 |         } => {
120 |             let output_preview = truncate_preview(&output, 600);
121 |             app.state.messages.push(ChatMessage::new(
122 |                 if success {
123 |                     MessageType::System
124 |                 } else {
125 |                     MessageType::Error
126 |                 },
127 |                 format!(
128 |                     "Tool {}: {name}
129 | Output: {output_preview}",
130 |                     if success { "complete" } else { "failed" }
131 |                 ),
132 |             ));
133 |             app.state.status = format!("Tool finished: {name}");
134 |             app.state.scroll_to_bottom();
135 |         }
136 |         SessionEvent::TextChunk(_) => {}
137 |         SessionEvent::TextComplete(text) => {
138 |             app.state
139 |                 .messages
140 |                 .push(ChatMessage::new(MessageType::Assistant, text));
141 |             app.state.status = "Assistant replied".to_string();
142 |             app.state.scroll_to_bottom();
143 |         }
144 |         SessionEvent::ThinkingComplete(text) => {
145 |             if !text.is_empty() {
146 |                 app.state.messages.push(ChatMessage::new(
147 |                     MessageType::System,
148 |                     format!(
149 |                         "Thinking:
150 | {}",
151 |                         truncate_preview(&text, 600)
152 |                     ),
153 |                 ));
154 |                 app.state.scroll_to_bottom();
155 |             }
156 |         }
157 |         SessionEvent::UsageReport {
158 |             model,
159 |             prompt_tokens,
160 |             completion_tokens,
161 |             duration_ms,
162 |         } => {
163 |             app.state.status = format!(
164 |                 "Completed with model {model} • {} in / {} out • {} ms",
165 |                 prompt_tokens, completion_tokens, duration_ms
166 |             );
167 |         }
168 |         SessionEvent::SessionSync(updated) => {
169 |             *session = *updated;
170 |             app.state.session_id = Some(session.id.clone());
171 |         }
172 |         SessionEvent::Done => {
173 |             handle_processing_stopped(app, worker_bridge).await;
174 |             app.state.status = "Ready".to_string();
175 |         }
176 |         SessionEvent::Error(err) => {
177 |             handle_processing_stopped(app, worker_bridge).await;
178 |             app.state
179 |                 .messages
180 |                 .push(ChatMessage::new(MessageType::Error, err.clone()));
181 |             app.state.status = "Error".to_string();
182 |             app.state.scroll_to_bottom();
183 |         }
184 |     }
185 | }
