187 | pub async fn handle_event(
188 |     app: &mut App,
189 |     cwd: &Path,
190 |     session: &mut Session,
191 |     registry: &Option<Arc<ProviderRegistry>>,
192 |     worker_bridge: &Option<TuiWorkerBridge>,
193 |     event_tx: &mpsc::Sender<SessionEvent>,
194 |     result_tx: &mpsc::Sender<anyhow::Result<Session>>,
195 |     key: KeyEvent,
196 | ) -> anyhow::Result<bool> {
197 |     if key.kind != KeyEventKind::Press {
198 |         return Ok(false);
199 |     }
200 | 
201 |     match key.code {
202 |         KeyCode::Char('c') if key.modifiers.contains(KeyModifiers::CONTROL) => return Ok(true),
203 |         KeyCode::Char('q') if key.modifiers.contains(KeyModifiers::CONTROL) => return Ok(true),
204 |         KeyCode::Char('t') if key.modifiers.contains(KeyModifiers::CONTROL) => {
205 |             app.state.symbol_search.open();
206 |             app.state.status = "Symbol search".to_string();
207 |         }
208 |         KeyCode::Esc => handle_escape(app),
209 |         KeyCode::Tab if app.state.slash_suggestions_visible() => handle_tab(app),
210 |         KeyCode::Char('?') => toggle_help(app),
211 |         KeyCode::Up => handle_up(app),
212 |         KeyCode::Down => handle_down(app),
213 |         KeyCode::PageUp => handle_page_up(app),
214 |         KeyCode::PageDown => handle_page_down(app),
215 |         KeyCode::Home => handle_home(app),
216 |         KeyCode::End => handle_end(app),
217 |         KeyCode::Left => handle_left(app, key.modifiers),
218 |         KeyCode::Right => handle_right(app, key.modifiers),
219 |         KeyCode::Delete => handle_delete(app),
220 |         KeyCode::Enter if symbol_search_active(app) => handle_symbol_enter(app),

221 |         KeyCode::Enter => {
222 |             handle_enter(
223 |                 app,
224 |                 cwd,
225 |                 session,
226 |                 registry,
227 |                 worker_bridge,
228 |                 event_tx,
229 |                 result_tx,
230 |             )
231 |             .await
232 |         }
233 |         KeyCode::Backspace if app.state.view_mode == ViewMode::Sessions => {
234 |             app.state.session_filter_backspace();
235 |         }
236 |         KeyCode::Backspace => handle_backspace(app).await,
237 |         KeyCode::Char('g') if app.state.view_mode == ViewMode::Bus => handle_bus_g(app),
238 |         KeyCode::Char('c') if app.state.view_mode == ViewMode::Bus => handle_bus_c(app),
239 |         KeyCode::Char('/') if app.state.view_mode == ViewMode::Bus => handle_bus_slash(app),
240 |         KeyCode::Char(c) if app.state.view_mode == ViewMode::Sessions => {
241 |             handle_sessions_char(app, key.modifiers, c)
242 |         }
243 |         KeyCode::Char(c) => handle_char(app, key.modifiers, c).await,
244 |         _ => {}
245 |     }
246 | 
247 |     Ok(false)
248 | }
