501 | async fn handle_enter_sessions(app: &mut App, cwd: &Path, session: &mut Session) {
502 |     let session_id = app
503 |         .state
504 |         .filtered_sessions()
505 |         .get(app.state.selected_session)
506 |         .map(|(orig_idx, _)| app.state.sessions[*orig_idx].id.clone());
507 |     if let Some(session_id) = session_id {
508 |         match Session::load(&session_id).await {
509 |             Ok(loaded) => {
510 |                 *session = loaded;
511 |                 app.state.session_id = Some(session.id.clone());
512 |                 sync_messages_from_session(app, session);
513 |                 refresh_sessions(app, cwd).await;
514 |                 app.state.clear_session_filter();
515 |                 return_to_chat(app);
516 |                 app.state.status = format!(
517 |                     "Loaded session {}",
518 |                     session.title.clone().unwrap_or_else(|| session.id.clone())
519 |                 );
520 |             }
521 |             Err(err) => {
522 |                 app.state.status = format!("Failed to load session: {err}");
523 |             }
524 |         }
525 |     }
526 | }
