537 | async fn handle_enter_chat(
538 |     app: &mut App,
539 |     cwd: &Path,
540 |     session: &mut Session,
541 |     registry: &Option<Arc<ProviderRegistry>>,
542 |     worker_bridge: &Option<TuiWorkerBridge>,
543 |     event_tx: &mpsc::Sender<SessionEvent>,
544 |     result_tx: &mpsc::Sender<anyhow::Result<Session>>,
545 | ) {
546 |     if app.state.processing {
547 |         app.state.status = "Still processing previous request…".to_string();
548 |         return;
549 |     }
550 | 
551 |     let prompt = app.state.input.trim().to_string();
552 |     if !prompt.is_empty() {
553 |         app.state.push_history(prompt.clone());
554 |     }
555 | 
556 |     if prompt.starts_with('/') {
557 |         handle_slash_command(app, cwd, &prompt).await;
558 |         app.state.clear_input();
559 |         return;
560 |     }
561 | 
562 |     if prompt.is_empty() {
563 |         return;
564 |     }
565 | 
566 |     app.state
567 |         .messages
568 |         .push(ChatMessage::new(MessageType::User, prompt.clone()));
569 |     app.state.clear_input();
570 |     handle_processing_started(app, worker_bridge).await;
571 |     app.state.status = "Submitting prompt…".to_string();
572 |     app.state.scroll_to_bottom();
573 | 
574 |     if let Some(registry) = registry {
575 |         let mut session_for_task = session.clone();
576 |         let event_tx = event_tx.clone();
577 |         let result_tx = result_tx.clone();
578 |         let registry = Arc::clone(registry);
579 |         tokio::spawn(async move {
580 |             let result = session_for_task
581 |                 .prompt_with_events(&prompt, event_tx, registry)
582 |                 .await
583 |                 .map(|_| session_for_task);
584 |             let _ = result_tx.send(result).await;
585 |         });
586 |     } else {
587 |         handle_processing_stopped(app, worker_bridge).await;
588 |         app.state.messages.push(ChatMessage::new(
589 |             MessageType::Error,
590 |             "No providers available. Configure credentials first (for example: `codetether auth codex` or `codetether auth copilot`).",
591 |         ));
592 |         app.state.status = "No providers configured".to_string();
593 |         app.state.scroll_to_bottom();
594 |     }
595 | }
