642 | async fn handle_char(app: &mut App, modifiers: KeyModifiers, c: char) {
643 |     if !modifiers.contains(KeyModifiers::CONTROL)
644 |         && !modifiers.contains(KeyModifiers::ALT)
645 |         && symbol_search_active(app)
646 |     {
647 |         app.state.symbol_search.handle_char(c);
648 |         refresh_symbol_search(app).await;
649 |     } else if app.state.view_mode == ViewMode::Bus
650 |         && app.state.bus_log.filter_input_mode
651 |         && !modifiers.contains(KeyModifiers::CONTROL)
652 |         && !modifiers.contains(KeyModifiers::ALT)
