{"path":"src/tui/app/background.rs","content":"use std::path::Path;

use tokio::sync::mpsc;

use crate::bus::BusHandle;
use crate::session::{Session, SessionEvent};
use crate::tui::app::session_events::handle_session_event;
use crate::tui::app::helpers::{handle_processing_stopped, refresh_sessions};
use crate::tui::app::state::App;
use crate::tui::chat::message::{ChatMessage, MessageType};
use crate::tui::worker_bridge::TuiWorkerBridge;

pub async fn drain_background_updates(
    app: &mut App,
    cwd: &Path,
    session: &mut Session,
    bus_handle: &mut BusHandle,
    worker_bridge: &mut Option<TuiWorkerBridge>,
    event_rx: &mut mpsc::Receiver<SessionEvent>,
    result_rx: &mut mpsc::Receiver<anyhow::Result<Session>>,
) {
    ingest_bus_messages(app, bus_handle);
    queue_worker_tasks(app, worker_bridge);
    display_next_worker_task(app);
    apply_completed_sessions(app, cwd, session, worker_bridge, result_rx).await;
    apply_session_events(app, session, worker_bridge, event_rx).await;
}

fn ingest_bus_messages(app: &mut App, bus_handle: &mut BusHandle) {
    while let Some(envelope) = bus_handle.try_recv() {
        app.state.bus_log.ingest(&envelope);
    }
}

fn queue_worker_tasks(app: &mut App, worker_bridge: &mut Option<TuiWorkerBridge>) {
    if let Some(bridge) = worker_bridge.as_mut() {
        while let Ok(task) = bridge.task_rx.try_recv() {
            let preview = format!(
                "{} from {}",
                task.task_id,
                task.from_agent
                    .clone()
                    .unwrap_or_else(|| "unknown".to_string())
            );
            app.state.push_recent_task(preview);
            app.state.enqueue_worker_task(task);
            app.state.status = format!(
                "Queued remote task(s): {}",
                app.state.worker_task_queue.len()
            );
        }
    }
}

fn display_next_worker_task(app: &mut App) {
    if !app.state.processing
        && let Some(task) = app.state.dequeue_worker_task()
    {
        let from_agent = task.from_agent.unwrap_or_else(|| "unknown".to_string());
        app.state.messages.push(ChatMessage::new(
            MessageType::System,
            format!(
                "Incoming A2A task {} from {}\n{}",
                task.task_id, from_agent, task.message
            ),
        ));
        app.state.status = format!("Received remote task {}", task.task_id);
        app.state.scroll_to_bottom();
    }
}

async fn apply_completed_sessions(
    app: &mut App,
    cwd: &Path,
    session: &mut Session,
    worker_bridge: &mut Option<TuiWorkerBridge>,
    result_rx: &mut mpsc::Receiver<anyhow::Result<Session>>,
) {
    while let Ok(updated_session) = result_rx.try_recv() {
        match updated_session {
            Ok(updated_session) => {
                *session = updated_session;
                app.state.session_id = Some(session.id.clone());
                let _ = session.save().await;
                refresh_sessions(app, cwd).await;
            }
            Err(err) => {
                handle_processing_stopped(app, worker_bridge).await;
                app.state
                    .messages
                    .push(ChatMessage::new(MessageType::Error, err.to_string()));
                app.state.status = "Request failed".to_string();
                app.state.scroll_to_bottom();
            }
        }
    }
}

async fn apply_session_events(
    app: &mut App,
    session: &mut Session,
    worker_bridge: &Option<TuiWorkerBridge>,
    event_rx: &mut mpsc::Receiver<SessionEvent>,
) {
    while let Ok(evt) = event_rx.try_recv() {
        handle_session_event(app, session, worker_bridge, evt).await;
    }
}
"}

{"path":"src/tui/app/session_events.rs","content":"use crate::session::{Session, SessionEvent};
use crate::tui::app::helpers::{
    handle_processing_started, handle_processing_stopped, truncate_preview,
};
use crate::tui::app::state::App;
use crate::tui::chat::message::{ChatMessage, MessageType};
use crate::tui::worker_bridge::TuiWorkerBridge;

pub async fn handle_session_event(
    app: &mut App,
    session: &mut Session,
    worker_bridge: &Option<TuiWorkerBridge>,
    evt: SessionEvent,
) {
    match evt {
        SessionEvent::Thinking => {
            handle_processing_started(app, worker_bridge).await;
            app.state.status = "Thinking…".to_string();
        }
        SessionEvent::ToolCallStart { name, arguments } => {
            handle_processing_started(app, worker_bridge).await;
            app.state.status = format!("Running tool: {name}");
            let args_preview = truncate_preview(&arguments, 240);
            app.state.messages.push(ChatMessage::new(
                MessageType::System,
                format!("Tool start: {name}\nArgs: {args_preview}"),
            ));
            app.state.scroll_to_bottom();
        }
        SessionEvent::ToolCallComplete {
            name,
            output,
            success,
        } => {
            let output_preview = truncate_preview(&output, 600);
            app.state.messages.push(ChatMessage::new(
                if success {
                    MessageType::System
                } else {
                    MessageType::Error
                },
                format!(
                    "Tool {}: {name}\nOutput: {output_preview}",
                    if success { "complete" } else { "failed" }
                ),
            ));
            app.state.status = format!("Tool finished: {name}");
            app.state.scroll_to_bottom();
        }
        SessionEvent::TextChunk(_) => {}
        SessionEvent::TextComplete(text) => {
            app.state
                .messages
                .push(ChatMessage::new(MessageType::Assistant, text));
            app.state.status = "Assistant replied".to_string();
            app.state.scroll_to_bottom();
        }
        SessionEvent::ThinkingComplete(text) => {
            if !text.is_empty() {
                app.state.messages.push(ChatMessage::new(
                    MessageType::System,
                    format!("Thinking:\n{}", truncate_preview(&text, 600)),
                ));
                app.state.scroll_to_bottom();
            }
        }
        SessionEvent::UsageReport {
            model,
            prompt_tokens,
            completion_tokens,
            duration_ms,
        } => {
            app.state.status = format!(
                "Completed with model {model} • {} in / {} out • {} ms",
                prompt_tokens, completion_tokens, duration_ms
            );
        }
        SessionEvent::SessionSync(updated) => {
            *session = *updated;
            app.state.session_id = Some(session.id.clone());
        }
        SessionEvent::Done => {
            handle_processing_stopped(app, worker_bridge).await;
            app.state.status = "Ready".to_string();
        }
        SessionEvent::Error(err) => {
            handle_processing_stopped(app, worker_bridge).await;
            app.state
                .messages
                .push(ChatMessage::new(MessageType::Error, err.clone()));
            app.state.status = "Error".to_string();
            app.state.scroll_to_bottom();
        }
    }
}
"}

{"path":"src/tui/app/navigation.rs","content":"use crossterm::event::KeyModifiers;

use crate::tui::app::helpers::{return_to_chat, symbol_search_active};
use crate::tui::app::state::App;
use crate::tui::models::{InputMode, ViewMode};

pub fn handle_escape(app: &mut App) {
    if symbol_search_active(app) {
        app.state.symbol_search.close();
        app.state.status = "Closed symbol search".to_string();
    } else if app.state.show_help {
        app.state.show_help = false;
        app.state.status = "Closed help".to_string();
    } else {
        match app.state.view_mode {
            ViewMode::Sessions => {
                app.state.clear_session_filter();
                return_to_chat(app);
            }
            ViewMode::Swarm if app.state.swarm.detail_mode => app.state.swarm.exit_detail(),
            ViewMode::Ralph if app.state.ralph.detail_mode => app.state.ralph.exit_detail(),
            ViewMode::Bus if app.state.bus_log.filter_input_mode => {
                app.state.bus_log.exit_filter_mode();
                app.state.status = "Protocol filter closed".to_string();
            }
            ViewMode::Bus if app.state.bus_log.detail_mode => app.state.bus_log.exit_detail(),
            ViewMode::Chat => app.state.input_mode = InputMode::Normal,
            _ => return_to_chat(app),
        }
    }
}

pub fn handle_tab(app: &mut App) {
    if app.state.apply_selected_slash_suggestion() {
        app.state.status = "Command autocompleted".to_string();
    }
}

pub fn toggle_help(app: &mut App) {
    app.state.show_help = !app.state.show_help;
    app.state.help_scroll.offset = 0;
    app.state.status = if app.state.show_help {
        "Help".to_string()
    } else {
        "Closed help".to_string()
    };
}

pub fn handle_up(app: &mut App) {
    if symbol_search_active(app) {
        app.state.symbol_search.select_prev();
        return;
    }
    if app.state.view_mode == ViewMode::Sessions {
        app.state.sessions_select_prev();
        return;
    }
    if app.state.slash_suggestions_visible() {
        app.state.select_prev_slash_suggestion();
        return;
    }
    if app.state.view_mode == ViewMode::Chat && !app.state.processing {
        let _ = app.state.history_prev();
        return;
    }
    if app.state.show_help {
        app.state.help_scroll.scroll_up(1);
        return;
    }

    match app.state.view_mode {
        ViewMode::Swarm => {
            if app.state.swarm.detail_mode {
                app.state.swarm.detail_scroll_up(1);
            } else {
                app.state.swarm.select_prev();
            }
        }
        ViewMode::Ralph => {
            if app.state.ralph.detail_mode {
                app.state.ralph.detail_scroll_up(1);
            } else {
                app.state.ralph.select_prev();
            }
        }
        ViewMode::Bus if !app.state.bus_log.filter_input_mode => {
            if app.state.bus_log.detail_mode {
                app.state.bus_log.detail_scroll_up(1);
            } else {
                app.state.bus_log.select_prev();
            }
        }
        _ => app.state.scroll_up(1),
    }
}

pub fn handle_down(app: &mut App) {
    if symbol_search_active(app) {
        app.state.symbol_search.select_next();
        return;
    }
    if app.state.view_mode == ViewMode::Sessions {
        app.state.sessions_select_next();
        return;
    }
    if app.state.slash_suggestions_visible() {
        app.state.select_next_slash_suggestion();
        return;
    }
    if app.state.view_mode == ViewMode::Chat && !app.state.processing {
        let _ = app.state.history_next();
        return;
    }
    if app.state.show_help {
        app.state.help_scroll.scroll_down(1, 200);
        return;
    }

    match app.state.view_mode {
        ViewMode::Swarm => {
            if app.state.swarm.detail_mode {
                app.state.swarm.detail_scroll_down(1);
            } else {
                app.state.swarm.select_next();
            }
        }
        ViewMode::Ralph => {
            if app.state.ralph.detail_mode {
                app.state.ralph.detail_scroll_down(1);
            } else {
                app.state.ralph.select_next();
            }
        }
        ViewMode::Bus if !app.state.bus_log.filter_input_mode => {
            if app.state.bus_log.detail_mode {
                app.state.bus_log.detail_scroll_down(1);
            } else {
                app.state.bus_log.select_next();
            }
        }
        _ => app.state.scroll_down(1),
    }
}

pub fn handle_page_up(app: &mut App) {
    if app.state.show_help {
        app.state.help_scroll.scroll_up(10);
        return;
    }

    match app.state.view_mode {
        ViewMode::Swarm if app.state.swarm.detail_mode => app.state.swarm.detail_scroll_up(10),
        ViewMode::Ralph if app.state.ralph.detail_mode => app.state.ralph.detail_scroll_up(10),
        ViewMode::Bus if app.state.bus_log.detail_mode => app.state.bus_log.detail_scroll_up(10),
        ViewMode::Chat => app.state.scroll_up(10),
        _ => {}
    }
}

pub fn handle_page_down(app: &mut App) {
    if app.state.show_help {
        app.state.help_scroll.scroll_down(10, 200);
        return;
    }

    match app.state.view_mode {
        ViewMode::Swarm if app.state.swarm.detail_mode => app.state.swarm.detail_scroll_down(10),
        ViewMode::Ralph if app.state.ralph.detail_mode => app.state.ralph.detail_scroll_down(10),
        ViewMode::Bus if app.state.bus_log.detail_mode => app.state.bus_log.detail_scroll_down(10),
        ViewMode::Chat => app.state.scroll_down(10),
        _ => {}
    }
}

pub fn handle_home(app: &mut App) {
    if app.state.view_mode == ViewMode::Chat {
        app.state.move_cursor_home();
    }
}

pub fn handle_end(app: &mut App) {
    if app.state.view_mode == ViewMode::Chat {
        app.state.move_cursor_end();
    }
}

pub fn handle_left(app: &mut App, modifiers: KeyModifiers) {
    if app.state.view_mode == ViewMode::Chat && !app.state.processing {
        if modifiers.contains(KeyModifiers::CONTROL) {
            app.state.move_cursor_word_left();
        } else {
            app.state.move_cursor_left();
        }
    }
}

pub fn handle_right(app: &mut App, modifiers: KeyModifiers) {
    if app.state.view_mode == ViewMode::Chat && !app.state.processing {
        if modifiers.contains(KeyModifiers::CONTROL) {
            app.state.move_cursor_word_right();
        } else {
            app.state.move_cursor_right();
        }
    }
}

pub fn handle_delete(app: &mut App) {
    if app.state.view_mode == ViewMode::Chat && !app.state.processing {
        app.state.delete_forward();
    }
}

pub fn handle_symbol_enter(app: &mut App) {
    if let Some(symbol) = app.state.symbol_search.selected_symbol() {
        app.state.status = format!(
            "Selected symbol {} {}",
            symbol.name,
            symbol
                .line
                .map(|line| format!("at line {line}"))
                .unwrap_or_default()
        );
    }
    app.state.symbol_search.close();
}
"}

{"path":"src/tui/app/input.rs","content":"use std::path::Path;
use std::sync::Arc;

use crossterm::event::KeyModifiers;
use tokio::sync::mpsc;

use crate::provider::ProviderRegistry;
use crate::session::{Session, SessionEvent};
use crate::tui::app::commands::handle_slash_command;
use crate::tui::app::helpers::{
    handle_processing_started, handle_processing_stopped, refresh_sessions,
    refresh_symbol_search, return_to_chat, symbol_search_active, sync_messages_from_session,
};
use crate::tui::app::state::App;
use crate::tui::chat::message::{ChatMessage, MessageType};
use crate::tui::models::{InputMode, ViewMode};
use crate::tui::worker_bridge::TuiWorkerBridge;

pub async fn handle_enter(
    app: &mut App,
    cwd: &Path,
    session: &mut Session,
    registry: &Option<Arc<ProviderRegistry>>,
    worker_bridge: &Option<TuiWorkerBridge>,
    event_tx: &mpsc::Sender<SessionEvent>,
    result_tx: &mpsc::Sender<anyhow::Result<Session>>,
) {
    match app.state.view_mode {
        ViewMode::Sessions => handle_enter_sessions(app, cwd, session).await,
        ViewMode::Swarm => app.state.swarm.enter_detail(),
        ViewMode::Ralph => app.state.ralph.enter_detail(),
        ViewMode::Bus if app.state.bus_log.filter_input_mode => handle_enter_bus_filter(app),
        ViewMode::Bus => app.state.bus_log.enter_detail(),
        ViewMode::Chat => {
            handle_enter_chat(
                app,
                cwd,
                session,
                registry,
                worker_bridge,
                event_tx,
                result_tx,
            )
            .await
        }
        ViewMode::Settings | ViewMode::Lsp | ViewMode::Rlm => {}
    }
}

pub async fn handle_backspace(app: &mut App) {
    if symbol_search_active(app) {
        app.state.symbol_search.handle_backspace();
        refresh_symbol_search(app).await;
    } else if app.state.view_mode == ViewMode::Bus && app.state.bus_log.filter_input_mode {
        app.state.bus_log.pop_filter_char();
        app.state.status = if app.state.bus_log.filter.is_empty() {
            "Protocol filter cleared".to_string()
        } else {
            format!("Protocol filter: {}", app.state.bus_log.filter)
        };
    } else if app.state.view_mode == ViewMode::Chat && !app.state.processing {
        app.state.delete_backspace();
        if app.state.input.is_empty() {
            app.state.input_mode = InputMode::Normal;
        } else if app.state.input.starts_with('/') {
            app.state.input_mode = InputMode::Command;
        }
    }
}

pub fn handle_bus_g(app: &mut App) {
    let len = app.state.bus_log.visible_count();
    if len > 0 {
        app.state.bus_log.selected_index = len - 1;
        app.state.bus_log.auto_scroll = true;
    }
}

pub fn handle_bus_c(app: &mut App) {
    app.state.bus_log.clear_filter();
    app.state.status = "Protocol filter cleared".to_string();
}

pub fn handle_bus_slash(app: &mut App) {
    app.state.bus_log.enter_filter_mode();
    app.state.status = "Protocol filter mode".to_string();
}

pub fn handle_sessions_char(app: &mut App, modifiers: KeyModifiers, c: char) {
    if !modifiers.contains(KeyModifiers::CONTROL) && !modifiers.contains(KeyModifiers::ALT) {
        app.state.session_filter_push(c);
    }
}

pub async fn handle_char(app: &mut App, modifiers: KeyModifiers, c: char) {
    if !modifiers.contains(KeyModifiers::CONTROL)
        && !modifiers.contains(KeyModifiers::ALT)
        && symbol_search_active(app)
    {
        app.state.symbol_search.handle_char(c);
        refresh_symbol_search(app).await;
    } else if app.state.view_mode == ViewMode::Bus
        && app.state.bus_log.filter_input_mode
        && !modifiers.contains(KeyModifiers::CONTROL)
        && !modifiers.contains(KeyModifiers::ALT)
    {
        app.state.bus_log.push_filter_char(c);
        app.state.status = format!("Protocol filter: {}", app.state.bus_log.filter);
    } else if app.state.view_mode == ViewMode::Chat
        && !modifiers.contains(KeyModifiers::CONTROL)
        && !modifiers.contains(KeyModifiers::ALT)
        && !app.state.processing
    {
        app.state.input_mode = if app.state.input.is_empty() && c == '/' {
            InputMode::Command
        } else if app.state.input.starts_with('/') || c == '/' {
            InputMode::Command
        } else {
            InputMode::Editing
        };
        app.state.insert_char(c);
    }
}

async fn handle_enter_sessions(app: &mut App, cwd: &Path, session: &mut Session) {
    let session_id = app
        .state
        .filtered_sessions()
        .get(app.state.selected_session)
        .map(|(orig_idx, _)| app.state.sessions[*orig_idx].id.clone());
    if let Some(session_id) = session_id {
        match Session::load(&session_id).await {
            Ok(loaded) => {
                *session = loaded;
                app.state.session_id = Some(session.id.clone());
                sync_messages_from_session(app, session);
                refresh_sessions(app, cwd).await;
                app.state.clear_session_filter();
                return_to_chat(app);
                app.state.status = format!(
                    "Loaded session {}",
                    session.title.clone().unwrap_or_else(|| session.id.clone())
                );
            }
            Err(err) => {
                app.state.status = format!("Failed to load session: {err}");
            }
        }
    }
}

fn handle_enter_bus_filter(app: &mut App) {
    app.state.bus_log.exit_filter_mode();
    app.state.status = if app.state.bus_log.filter.is_empty() {
        "Protocol filter cleared".to_string()
    } else {
        format!("Protocol filter applied: {}", app.state.bus_log.filter)
    };
}

async fn handle_enter_chat(
    app: &mut App,
    cwd: &Path,
    session: &mut Session,
    registry: &Option<Arc<ProviderRegistry>>,
    worker_bridge: &Option<TuiWorkerBridge>,
    event_tx: &mpsc::Sender<SessionEvent>,
    result_tx: &mpsc::Sender<anyhow::Result<Session>>,
) {
    if app.state.processing {
        app.state.status = "Still processing previous request…".to_string();
        return;
    }

    let prompt = app.state.input.trim().to_string();
    if !prompt.is_empty() {
        app.state.push_history(prompt.clone());
    }

    if prompt.starts_with('/') {
        handle_slash_command(app, cwd, &prompt).await;
        app.state.clear_input();
        return;
    }

    if prompt.is_empty() {
        return;
    }

    app.state
        .messages
        .push(ChatMessage::new(MessageType::User, prompt.clone()));
    app.state.clear_input();
    handle_processing_started(app, worker_bridge).await;
    app.state.status = "Submitting prompt…".to_string();
    app.state.scroll_to_bottom();

    if let Some(registry) = registry {
        let mut session_for_task = session.clone();
        let event_tx = event_tx.clone();
        let result_tx = result_tx.clone();
        let registry = Arc::clone(registry);
        tokio::spawn(async move {
            let result = session_for_task
                .prompt_with_events(&prompt, event_tx, registry)
                .await
                .map(|_| session_for_task);
            let _ = result_tx.send(result).await;
        });
    } else {
        handle_processing_stopped(app, worker_bridge).await;
        app.state.messages.push(ChatMessage::new(
            MessageType::Error,
            "No providers available. Configure credentials first (for example: `codetether auth codex` or `codetether auth copilot`).",
        ));
        app.state.status = "No providers configured".to_string();
        app.state.scroll_to_bottom();
    }
}
"}

{"path":"src/tui/app/event_handlers.rs","content":"use std::path::Path;
use std::sync::Arc;

use crossterm::event::{KeyCode, KeyEvent, KeyEventKind};
use tokio::sync::mpsc;

use crate::provider::ProviderRegistry;
use crate::session::{Session, SessionEvent};
use crate::tui::app::input::{
    handle_backspace, handle_bus_c, handle_bus_g, handle_bus_slash, handle_char, handle_enter,
    handle_sessions_char,
};
use crate::tui::app::navigation::{
    handle_delete, handle_down, handle_end, handle_escape, handle_home, handle_left,
    handle_page_down, handle_page_up, handle_right, handle_symbol_enter, handle_tab, handle_up,
    toggle_help,
};
use crate::tui::app::helpers::symbol_search_active;
use crate::tui::app::state::App;
use crate::tui::models::ViewMode;
use crate::tui::worker_bridge::TuiWorkerBridge;

pub async fn handle_event(
    app: &mut App,
    cwd: &Path,
    session: &mut Session,
    registry: &Option<Arc<ProviderRegistry>>,
    worker_bridge: &Option<TuiWorkerBridge>,
    event_tx: &mpsc::Sender<SessionEvent>,
    result_tx: &mpsc::Sender<anyhow::Result<Session>>,
    key: KeyEvent,
) -> anyhow::Result<bool> {
    if key.kind != KeyEventKind::Press {
        return Ok(false);
    }

    match key.code {
        KeyCode::Char('c') if key.modifiers.contains(crossterm::event::KeyModifiers::CONTROL) => {
            return Ok(true);
        }
        KeyCode::Char('q') if key.modifiers.contains(crossterm::event::KeyModifiers::CONTROL) => {
            return Ok(true);
        }
        KeyCode::Char('t') if key.modifiers.contains(crossterm::event::KeyModifiers::CONTROL) => {
            app.state.symbol_search.open();
            app.state.status = "Symbol search".to_string();
        }
        KeyCode::Esc => handle_escape(app),
        KeyCode::Tab if app.state.slash_suggestions_visible() => handle_tab(app),
        KeyCode::Char('?') => toggle_help(app),
        KeyCode::Up => handle_up(app),
        KeyCode::Down => handle_down(app),
        KeyCode::PageUp => handle_page_up(app),
        KeyCode::PageDown => handle_page_down(app),
        KeyCode::Home => handle_home(app),
        KeyCode::End => handle_end(app),
        KeyCode::Left => handle_left(app, key.modifiers),
        KeyCode::Right => handle_right(app, key.modifiers),
        KeyCode::Delete => handle_delete(app),
        KeyCode::Enter if symbol_search_active(app) => handle_symbol_enter(app),
        KeyCode::Enter => {
            handle_enter(
                app,
                cwd,
                session,
                registry,
                worker_bridge,
                event_tx,
                result_tx,
            )
            .await;
        }
        KeyCode::Backspace if app.state.view_mode == ViewMode::Sessions => {
            app.state.session_filter_backspace();
        }
        KeyCode::Backspace => handle_backspace(app).await,
        KeyCode::Char('g') if app.state.view_mode == ViewMode::Bus => handle_bus_g(app),
        KeyCode::Char('c') if app.state.view_mode == ViewMode::Bus => handle_bus_c(app),
        KeyCode::Char('/') if app.state.view_mode == ViewMode::Bus => handle_bus_slash(app),
        KeyCode::Char(c) if app.state.view_mode == ViewMode::Sessions => {
            handle_sessions_char(app, key.modifiers, c)
        }
        KeyCode::Char(c) => handle_char(app, key.modifiers, c).await,
        _ => {}
    }

    Ok(false)
}
