         for (idx, msg) in app.state.messages.iter().enumerate() {
             let (label, role, icon) = match msg.message_type {
                 MessageType::User => ("user", "user", "▸ "),
                 MessageType::Assistant => ("assistant", "assistant", "◆ "),
                 MessageType::System => ("system", "system", "⚙ "),
                 MessageType::Error => ("error", "error", "✖ "),
             };
             let color = palette.get_message_color(role);
             if idx > 0 {
                 let sep = if role == "system" || role == "error" {
                     "·"
