124 |     fn char_to_byte_index(&self, char_index: usize) -> usize {
125 |         if char_index == 0 {
126 |             return 0;
127 |         }
128 |         self.input
129 |             .char_indices()
130 |             .nth(char_index)
131 |             .map(|(idx, _)| idx)
132 |             .unwrap_or_else(|| self.input.len())
133 |     }
