139 |     pub fn clamp_input_cursor(&mut self) {
140 |         self.input_cursor = self.input_cursor.min(self.input_char_count());
141 |     }
142 | 
143 |     pub fn ensure_input_cursor_visible(&mut self, visible_width: usize) {
144 |         if visible_width == 0 {
145 |             self.input_scroll = self.input_cursor;
146 |             return;
147 |         }
148 |         if self.input_cursor < self.input_scroll {
149 |             self.input_scroll = self.input_cursor;
150 |         } else if self.input_cursor >= self.input_scroll.saturating_add(visible_width) {
151 |             self.input_scroll = self
152 |                 .input_cursor
153 |                 .saturating_sub(visible_width.saturating_sub(1));
154 |         }
155 |     }
