157 |     pub fn move_cursor_left(&mut self) {
158 |         if self.input_cursor > 0 {
159 |             self.input_cursor -= 1;
160 |         }
161 |     }
162 | 
163 |     pub fn move_cursor_right(&mut self) {
164 |         if self.input_cursor < self.input_char_count() {
165 |             self.input_cursor += 1;
166 |         }
167 |     }
