169 |     pub fn move_cursor_word_left(&mut self) {
170 |         self.clamp_input_cursor();
171 |         while self.input_cursor > 0
172 |             && self
173 |                 .char_at(self.input_cursor - 1)
174 |                 .is_some_and(char::is_whitespace)
175 |         {
176 |             self.input_cursor -= 1;
177 |         }
178 |         while self.input_cursor > 0
179 |             && self
180 |                 .char_at(self.input_cursor - 1)
181 |                 .is_some_and(|c| !c.is_whitespace())
182 |         {
183 |             self.input_cursor -= 1;
184 |         }
185 |     }
186 | 
187 |     pub fn move_cursor_word_right(&mut self) {
188 |         self.clamp_input_cursor();
189 |         while self.input_cursor < self.input_char_count()
190 |             && self
191 |                 .char_at(self.input_cursor)
192 |                 .is_some_and(char::is_whitespace)
193 |         {
194 |             self.input_cursor += 1;
195 |         }
196 |         while self.input_cursor < self.input_char_count()
197 |             && self
198 |                 .char_at(self.input_cursor)
199 |                 .is_some_and(|c| !c.is_whitespace())
200 |         {
201 |             self.input_cursor += 1;
202 |         }
203 |     }
