410 |     pub fn history_prev(&mut self) -> bool {
411 |         if self.command_history.is_empty() {
412 |             return false;
413 |         }
414 |         let history_len = self.command_history.len();
415 |         let new_index = match self.history_index {
416 |             Some(index) if index > 0 => Some(index - 1),
417 |             Some(index) => Some(index),
418 |             None => Some(history_len - 1),
419 |         };
420 |         if let Some(index) = new_index {
421 |             self.history_index = Some(index);
422 |             self.input = self.command_history[index].clone();
423 |             self.input_cursor = self.input_char_count();
424 |             self.input_mode = if self.input.starts_with('/') {
425 |                 InputMode::Command
426 |             } else {
427 |                 InputMode::Editing
428 |             };
429 |             self.refresh_slash_suggestions();
430 |             return true;
431 |         }
432 |         false
433 |     }
