435 |     pub fn history_next(&mut self) -> bool {
436 |         if self.command_history.is_empty() {
437 |             return false;
438 |         }
439 |         match self.history_index {
440 |             Some(index) if index + 1 < self.command_history.len() => {
441 |                 let next = index + 1;
442 |                 self.history_index = Some(next);
443 |                 self.input = self.command_history[next].clone();
444 |             }
445 |             Some(_) => {
446 |                 self.history_index = None;
447 |                 self.input.clear();
448 |             }
449 |             None => return false,
450 |         }
451 |         self.input_cursor = self.input_char_count();
452 |         self.input_mode = if self.input.is_empty() {
453 |             InputMode::Normal
454 |         } else if self.input.starts_with('/') {
455 |             InputMode::Command
456 |         } else {
457 |             InputMode::Editing
458 |         };
459 |         self.refresh_slash_suggestions();

460 |         true
461 |     }
