 72 |     app.state.session_id = Some(session.id.clone());
 73 |     sync_messages_from_session(&mut app, &session);
 74 |     refresh_sessions(&mut app, &cwd).await;
 75 |     if let Some(bridge) = worker_bridge.as_ref() {
 76 |         app.state
 77 |             .set_worker_bridge(bridge.worker_id.clone(), bridge.worker_name.clone());
 78 |         app.state.register_worker_agent("tui".to_string());
 79 |     }
 80 |     let _ = app.state.refresh_available_models(registry.as_ref()).await;
 81 |     app.state.refresh_slash_suggestions();
 82 |     app.state.move_cursor_end();
 83 |     app.state.status = if app.state.messages.is_empty() {
 84 |         "Ready — type a message, or use /help for commands.".to_string()
 85 |     } else {
 86 |         "Loaded previous workspace session".to_string()
 87 |     };
 88 | 
 89 |     run_event_loop(
 90 |         &mut terminal,
 91 |         &mut app,
 92 |         &cwd,
 93 |         registry,
 94 |         &mut session,
 95 |         &mut bus_handle,
 96 |         worker_bridge,
 97 |         event_tx,
 98 |         event_rx,
 99 |         result_tx,
100 |         result_rx,
101 |     )
102 |     .await?;
103 | 
104 |     terminal.show_cursor()?;
105 |     Ok(())
106 | }

