 11 |     handle_sessions_char,
 12 | };
 13 | use crate::tui::app::navigation::{
 14 |     handle_delete, handle_down, handle_end, handle_escape, handle_home, handle_left,
 15 |     handle_page_down, handle_page_up, handle_right, handle_symbol_enter, handle_tab, handle_up,
 16 |     toggle_help,
 17 | };
 18 | use crate::tui::app::state::App;
 19 | use crate::tui::app::symbols::symbol_search_active;
 20 | use crate::tui::models::ViewMode;
 21 | use crate::tui::worker_bridge::TuiWorkerBridge;
 22 | 
 23 | pub async fn handle_event(
 24 |     app: &mut App,
 25 |     cwd: &Path,
 26 |     session: &mut Session,
 27 |     registry: &Option<Arc<ProviderRegistry>>,
 28 |     worker_bridge: &Option<TuiWorkerBridge>,
 29 |     event_tx: &mpsc::Sender<SessionEvent>,
 30 |     result_tx: &mpsc::Sender<anyhow::Result<Session>>,
 31 |     key: KeyEvent,
 32 | ) -> anyhow::Result<bool> {
 33 |     if key.kind != KeyEventKind::Press {
 34 |         return Ok(false);
 35 |     }
 36 | 
 37 |     match key.code {
 38 |         KeyCode::Char('c')
 39 |             if key
 40 |                 .modifiers
 41 |                 .contains(crossterm::event::KeyModifiers::CONTROL) =>
 42 |         {
 43 |             return Ok(true);
 44 |         }
 45 |         KeyCode::Char('q')
 46 |             if key
 47 |                 .modifiers
 48 |                 .contains(crossterm::event::KeyModifiers::CONTROL) =>
 49 |         {
 50 |             return Ok(true);
 51 |         }
 52 |         KeyCode::Char('t')
 53 |             if key
 54 |                 .modifiers
 55 |                 .contains(crossterm::event::KeyModifiers::CONTROL) =>
 56 |         {
 57 |             app.state.symbol_search.open();
 58 |             app.state.status = "Symbol search".to_string();
 59 |         }
 60 |         KeyCode::Esc => handle_escape(app),
 61 |         KeyCode::Tab if app.state.slash_suggestions_visible() => handle_tab(app),
 62 |         KeyCode::Char('?') => toggle_help(app),
 63 |         KeyCode::Up => handle_up(app),
 64 |         KeyCode::Down => handle_down(app),
 65 |         KeyCode::PageUp => handle_page_up(app),
 66 |         KeyCode::PageDown => handle_page_down(app),
 67 |         KeyCode::Home => handle_home(app),
 68 |         KeyCode::End => handle_end(app),
 69 |         KeyCode::Left => handle_left(app, key.modifiers),
 70 |         KeyCode::Right => handle_right(app, key.modifiers),
 71 |         KeyCode::Delete => handle_delete(app),
 72 |         KeyCode::Enter if symbol_search_active(app) => handle_symbol_enter(app),
 73 |         KeyCode::Enter => {
 74 |             handle_enter(
 75 |                 app,
 76 |                 cwd,
 77 |                 session,
 78 |                 registry,
 79 |                 worker_bridge,
 80 |                 event_tx,
 81 |                 result_tx,
 82 |             )
 83 |             .await;
 84 |         }
 85 |         KeyCode::Backspace if app.state.view_mode == ViewMode::Sessions => {
 86 |             app.state.session_filter_backspace();
 87 |         }
 88 |         KeyCode::Backspace => handle_backspace(app).await,
 89 |         KeyCode::Char('g') if app.state.view_mode == ViewMode::Bus => handle_bus_g(app),
 90 |         KeyCode::Char('c') if app.state.view_mode == ViewMode::Bus => handle_bus_c(app),
 91 |         KeyCode::Char('/') if app.state.view_mode == ViewMode::Bus => handle_bus_slash(app),
 92 |         KeyCode::Char(c) if app.state.view_mode == ViewMode::Sessions => {
 93 |             handle_sessions_char(app, key.modifiers, c)
 94 |         }
 95 |         KeyCode::Char(c) => handle_char(app, key.modifiers, c).await,
 96 |         _ => {}
 97 |     }
 98 | 
 99 |     Ok(false)
100 | }

